2	/**
3	 * AI Sandbox HTTP wrapper for the Test 7 batch runner.
4	 *
5	 * Listens on port 3000 (ALB requirement) and satisfies the health check at
6	 * GET / while providing a simple API to trigger and monitor batch runs.
7	 *
8	 * Routes:
9	 *   GET  /        — HTML status page; always returns 200 (ALB health check)
10	 *   GET  /status  — JSON run state
11	 *   GET  /logs    — plain-text log tail  (?n=N lines, default 100)
12	 *   POST /run     — start a run; body is JSON with optional overrides:
13	 *                     { models, scenarios, defences, reps,
14	 *                       s3Bucket, s3Prefix, s3Region, awsRegion, runId }
15	 *                   Returns 202 if accepted, 409 if a run is already in progress.
16	 */
17	
18	import http from "http";
19	import { spawn } from "child_process";
20	import { readFileSync } from "fs";
21	
22	const PORT = 3000;
23	const MAX_LOG_LINES = 500;
24	const ENTRYPOINT = "/docker-entrypoint.sh";
25	const BUILD_VERSION = JSON.parse(readFileSync(new URL("./package.json", import.meta.url), "utf8")).version;
26	
27	// ---------------------------------------------------------------------------
28	// Run state
29	// ---------------------------------------------------------------------------
30	
31	let state = {
32	  status: "idle",   // idle | running | done | failed
33	  runId: null,
34	  params: null,
35	  startedAt: null,
36	  finishedAt: null,
37	  exitCode: null,
38	  pid: null,
39	  logLines: [],
40	};
41	
42	let currentProcess = null;
43	
44	function appendLog(line) {
45	  state.logLines.push(line);
46	  if (state.logLines.length > MAX_LOG_LINES) state.logLines.shift();
47	  process.stdout.write(line + "\n");
48	}
49	
50	function startRun(params) {
51	  const env = Object.assign({}, process.env);
52	
53	  if (params.models)    env.TEST7_MODELS    = String(params.models);
54	  if (params.scenarios) env.TEST7_SCENARIOS = String(params.scenarios);
55	  if (params.defences)  env.TEST7_DEFENCES  = String(params.defences);
56	  if (params.reps)      env.TEST7_REPS      = String(params.reps);
57	  if (params.s3Bucket)  env.S3_BUCKET       = String(params.s3Bucket);
58	  if (params.s3Prefix)  env.S3_PREFIX       = String(params.s3Prefix);
59	  if (params.s3Region)  env.S3_REGION       = String(params.s3Region);
60	  if (params.awsRegion) env.AWS_REGION      = String(params.awsRegion);
61	  if (params.runId)     env.TEST7_RUN_ID    = String(params.runId);
62	
63	  const runId = env.TEST7_RUN_ID || new Date().toISOString().replace(/[:.]/g, "");
64	
65	  state = {
66	    status: "running",
67	    runId,
68	    params,
69	    startedAt: new Date().toISOString(),
70	    finishedAt: null,
71	    exitCode: null,
72	    pid: null,
73	    logLines: [],
74	  };
75	
76	  const child = spawn(ENTRYPOINT, [], {
77	    env,
78	    stdio: ["ignore", "pipe", "pipe"],
79	  });
80	
81	  state.pid = child.pid;
82	  currentProcess = child;
83	
84	  child.stdout.on("data", (data) => {
85	    data.toString().split("\n").filter(Boolean).forEach(appendLog);
86	  });
87	
88	  child.stderr.on("data", (data) => {
89	    data.toString().split("\n").filter(Boolean).forEach((l) => appendLog("[ERR] " + l));
90	  });
91	
92	  child.on("close", (code) => {
93	    state.status = code === 0 ? "done" : "failed";
94	    state.exitCode = code;
95	    state.finishedAt = new Date().toISOString();
96	    currentProcess = null;
97	    console.log(`Run ${runId} finished — exit code ${code}`);
98	  });
99	
100	  child.on("error", (err) => {
101	    state.status = "failed";
102	    state.exitCode = -1;
103	    state.finishedAt = new Date().toISOString();
104	    currentProcess = null;
105	    appendLog("[ERROR] Failed to spawn entrypoint: " + err.message);
106	  });
107	}
108	
109	// ---------------------------------------------------------------------------
110	// HTTP server
111	// ---------------------------------------------------------------------------
112	
113	const server = http.createServer((req, res) => {
114	  const url = new URL(req.url, "http://localhost:" + PORT);
115	
116	  // ── GET / — health check + status page ───────────────────────────────────
117	  if (req.method === "GET" && url.pathname === "/") {
118	    const colour = { idle: "#888", running: "#4af", done: "#4f4", failed: "#f44" }[state.status] || "#888";
